1	const BASE_PREMIUM = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	  rune: 25,
7	  moonstone: 25,
8	} as const;
9	
10	export type ItemType = keyof typeof BASE_PREMIUM;
11	
12	export type Item = { type: ItemType; cursed?: boolean; enchantment?: number };
13	
14	const BLOCK_SIZE = 3;
15	const BLOCK_PREMIUM = 60;
16	const COMPONENT_TYPES: ReadonlySet<ItemType> = new Set<ItemType>(["rune", "moonstone"]);
17	
18	function itemSurcharge(item: Item): number {
19	  const base = BASE_PREMIUM[item.type];
20	  let surcharge = 0;
21	  if (item.cursed) {
22	    surcharge += base * 0.5;
23	  }
24	  if (item.enchantment !== undefined && item.enchantment >= 5) {
25	    surcharge += base * 0.3;
26	  }
27	  return surcharge;
28	}
29	
30	export function calculateBasePremium(items: Item[]): number {
31	  const groups = new Map<ItemType, number>();
32	  let totalSurcharge = 0;
33	  for (const item of items) {
34	    groups.set(item.type, (groups.get(item.type) ?? 0) + 1);
35	    totalSurcharge += itemSurcharge(item);
36	  }
37	
38	  let total = 0;
39	  for (const [type, count] of groups) {
40	    if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
41	      total += BLOCK_PREMIUM;
42	    } else {
43	      total += count * BASE_PREMIUM[type];
44	    }
45	  }
46	  return total + totalSurcharge;
47	}
